using System.Collections.Generic;
using TMPro;
using UnityEngine;

/// <summary>
/// Roda de Animais (Tarefa #21 — "Roda de animais/itens"): UI radial que
/// aparece enquanto o jogador mantém o botão da Roda de Formas premido
/// (<see cref="PlayerInputRouter.FormWheelOpened"/>/<see cref="PlayerInputRouter.FormWheelClosed"/>),
/// mostrando todas as <see cref="FormSwitcher.unlockedForms"/> num círculo.
///
/// - Navegação: L/R (<see cref="PlayerInputRouter.PrevFormTapped"/>/<see cref="PlayerInputRouter.NextFormTapped"/>)
///   já mudam <see cref="FormSwitcher.SelectedIndex"/> via FormSwitcher
///   (OnSelectionChanged) sem trocar de forma enquanto a roda está aberta —
///   este componente só reflecte a selecção.
/// - Formas indisponíveis AGORA (<see cref="FormSwitcher.CanSwitchTo"/> ==
///   false — ex: no ar, submerso, em cooldown) aparecem acinzentadas com um
///   ícone de cadeado (<see cref="FormWheelNodeUI"/>); o motivo aparece em
///   <see cref="reasonText"/> quando essa forma está seleccionada.
/// - Confirmação: <see cref="PlayerInputRouter.ConfirmTransformHold"/> (já
///   ligado em FormSwitcher.OnConfirmTransformHold) aplica a forma
///   seleccionada.
/// - Cancelamento: soltar o botão da roda sem confirmar
///   (FormWheelClosed) fecha sem aplicar nada — a forma actual mantém-se.
/// - Câmara lenta: Time.timeScale ≈ 0.2 enquanto a roda estiver aberta
///   (<see cref="WheelTimeScaleUtil"/>), partilhado com a Roda de Itens.
///
/// Montagem no Editor:
/// - "panelRoot": GameObject raiz da roda (activado/desactivado ao abrir/fechar).
/// - "wheelContainer": RectTransform vazio, centro da roda — os nós são
///   instanciados como filhos, posicionados em círculo.
/// - "nodePrefab": prefab com <see cref="FormWheelNodeUI"/> (ícone + cadeado +
///   destaque + marcador de forma actual).
/// - "reasonText"/"formNameText": TMP_Text opcionais para nome/motivo da forma
///   seleccionada.
/// </summary>
public class FormWheelUI : MonoBehaviour
{
    [Header("Referências")]
    [SerializeField] private PlayerInputRouter input;
    [SerializeField] private FormSwitcher formSwitcher;

    [Header("UI")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private RectTransform wheelContainer;
    [SerializeField] private FormWheelNodeUI nodePrefab;

    [Tooltip("Nome da forma seleccionada (opcional).")]
    [SerializeField] private TMP_Text formNameText;

    [Tooltip("Motivo pelo qual a forma seleccionada está indisponível (vazio se disponível).")]
    [SerializeField] private TMP_Text reasonText;

    [Header("Layout (círculo)")]
    [SerializeField] private float radius = 180f;
    [Tooltip("Ângulo (graus) do primeiro nó, medido a partir do topo, sentido horário.")]
    [SerializeField] private float startAngleDeg = 0f;

    [Header("Câmara Lenta")]
    [Range(0.05f, 1f)]
    [SerializeField] private float slowTimeScale = 0.2f;

    private readonly List<FormWheelNodeUI> _nodes = new List<FormWheelNodeUI>();
    private bool _isOpen;

    private void Awake()
    {
        if (input == null) input = GetComponentInParent<PlayerInputRouter>();
        if (formSwitcher == null) formSwitcher = GetComponentInParent<FormSwitcher>();

        if (panelRoot != null) panelRoot.SetActive(false);
    }

    private void OnEnable()
    {
        if (input == null || formSwitcher == null)
        {
            Debug.LogError("[FormWheelUI] input/formSwitcher não atribuídos. Liga no Inspector.");
            enabled = false;
            return;
        }

        input.FormWheelOpened += OnWheelOpened;
        input.FormWheelClosed += OnWheelClosed;
        formSwitcher.OnSelectionChanged += OnSelectionChanged;
    }

    private void OnDisable()
    {
        if (input != null)
        {
            input.FormWheelOpened -= OnWheelOpened;
            input.FormWheelClosed -= OnWheelClosed;
        }

        if (formSwitcher != null)
            formSwitcher.OnSelectionChanged -= OnSelectionChanged;

        // Salvaguarda: se este componente for desactivado enquanto a roda
        // estava aberta, garante que a câmara lenta não fica "pendurada".
        if (_isOpen)
        {
            WheelTimeScaleUtil.EndSlowdown();
            _isOpen = false;
        }
    }

    private void Update()
    {
        if (!_isOpen) return;

        // Reavalia disponibilidade a cada frame: o estado do jogador (chão/
        // água/submerso/cooldown) pode mudar enquanto a roda está aberta,
        // mesmo em câmara lenta.
        RefreshAvailability();
    }

    private void OnWheelOpened()
    {
        _isOpen = true;

        if (panelRoot != null) panelRoot.SetActive(true);

        BuildNodes();
        RefreshAvailability();

        WheelTimeScaleUtil.BeginSlowdown(slowTimeScale);
    }

    private void OnWheelClosed()
    {
        if (!_isOpen) return;
        _isOpen = false;

        if (panelRoot != null) panelRoot.SetActive(false);

        WheelTimeScaleUtil.EndSlowdown();
    }

    private void OnSelectionChanged(int index)
    {
        RefreshAvailability();
    }

    /// <summary>
    /// (Re)cria um nó por forma desbloqueada, posicionado em círculo
    /// ("wheelContainer" como centro). Chamado ao abrir a roda — o número de
    /// formas desbloqueadas pode ter mudado desde a última vez.
    /// </summary>
    private void BuildNodes()
    {
        if (wheelContainer == null || nodePrefab == null) return;

        foreach (var node in _nodes)
            if (node != null) Destroy(node.gameObject);
        _nodes.Clear();

        var forms = formSwitcher.unlockedForms;
        int count = forms.Count;
        if (count == 0) return;

        float stepDeg = 360f / count;

        for (int i = 0; i < count; i++)
        {
            var node = Instantiate(nodePrefab, wheelContainer);
            node.gameObject.SetActive(true);

            float angleDeg = startAngleDeg + stepDeg * i;
            float angleRad = angleDeg * Mathf.Deg2Rad;

            // Ângulo medido a partir do topo (0° = topo), sentido horário.
            Vector2 pos = new Vector2(Mathf.Sin(angleRad), Mathf.Cos(angleRad)) * radius;
            node.GetComponent<RectTransform>().anchoredPosition = pos;

            _nodes.Add(node);
        }
    }

    /// <summary>
    /// Actualiza cada nó (acinzentado + cadeado se indisponível, destaque na
    /// forma seleccionada, marcador na forma actual) e o texto de nome/motivo
    /// da forma actualmente seleccionada.
    /// </summary>
    private void RefreshAvailability()
    {
        var forms = formSwitcher.unlockedForms;
        int selected = formSwitcher.SelectedIndex;
        var current = formSwitcher.CurrentForm;

        string selectedReason = null;
        AnimalFormData selectedForm = null;

        for (int i = 0; i < _nodes.Count && i < forms.Count; i++)
        {
            var form = forms[i];
            bool available = formSwitcher.CanSwitchTo(form, out string reason);
            bool isCurrent = form == current;
            bool isSelected = i == selected;

            _nodes[i].Setup(form, isCurrent, isSelected, available);

            if (isSelected)
            {
                selectedForm = form;
                selectedReason = available ? null : reason;
            }
        }

        if (formNameText != null)
            formNameText.text = selectedForm != null ? selectedForm.displayName : string.Empty;

        if (reasonText != null)
            reasonText.text = selectedReason ?? string.Empty;
    }
}
